/* RevMan-compatible PDF export.
 *
 * Adds a button next to the existing "Download PDF Report" in the
 * Scientific Output tab. On click:
 *   1. Temporarily reveals tab-report + tab-statistics + tab-extract
 *   2. Injects a Cochrane-style print stylesheet (page breaks, title block,
 *      PICO header, footer disclaimer, etc.)
 *   3. Calls window.print() so the user can save as PDF via the browser
 *   4. Cleans up after print dialog closes
 *
 * Output sections (in order):
 *   - Title + PICO + identifiers
 *   - PRISMA 2020 flow diagram
 *   - Risk of Bias 2 traffic light
 *   - Visual abstract (existing report content)
 *   - Statistical Suite: R metafor, NNT, Leave-one-out, GRADE SoF,
 *     Cumulative MA, Baujat, TSA, NMA league + forest (where applicable)
 *   - Footer disclaimer: "Generated by RapidMeta · Not a Cochrane
 *     Collaboration document"
 *
 * Pure additive: never touches existing downloadPDFReport() or any
 * existing button.
 */
(function (global) {
  'use strict';

  function buildPrintCSS() {
    return `
@media print {
  /* Reset all */
  body { background: white !important; color: black !important; font-family: 'Times New Roman', Georgia, serif; font-size: 10.5pt; line-height: 1.45; }
  body * { visibility: hidden; }

  /* Reveal: report + statistics + extract for full data */
  #tab-report, #tab-report *,
  #tab-statistics, #tab-statistics *,
  #cochrane-export-header, #cochrane-export-header *,
  #cochrane-export-footer, #cochrane-export-footer * { visibility: visible; }

  /* Lay them out top-to-bottom */
  #cochrane-export-header { position: relative; left: 0; top: 0; width: 100%; padding: 0 0 12px 0; border-bottom: 2px solid #000; margin-bottom: 16px; page-break-after: avoid; }
  #tab-report { position: relative; left: 0; top: 0; width: 100%; padding: 8px 0; page-break-before: auto; }
  #tab-statistics { position: relative; left: 0; top: 0; width: 100%; padding: 8px 0; page-break-before: always; }
  #cochrane-export-footer { position: relative; left: 0; bottom: 0; width: 100%; padding: 12px 0 0 0; border-top: 1px solid #000; margin-top: 24px; font-size: 9pt; font-style: italic; }

  /* Make all panel bodies open during print */
  #tab-statistics div[id$="-panel"] > div:nth-child(2),
  #tab-statistics #r-validation-badge > div:nth-child(2),
  #tab-statistics .r-validation-badge-panel > div:nth-child(2) { display: block !important; padding-top: 4px !important; }

  /* Hide UI chrome */
  header, nav, .tab-btn, #stale-banner, #toast-container,
  .no-print, button, [onclick] { display: none !important; }

  /* Glass / dark theme to print-friendly */
  .glass, [class*="bg-slate-9"], [class*="bg-slate-8"] { background: white !important; border: 1px solid #ccc !important; color: #000 !important; backdrop-filter: none !important; }
  #tab-report *, #tab-statistics * { color: #000 !important; }
  /* Keep panel summary chips visible */
  #tab-statistics span[style*="background:#1e3a5f"],
  #tab-statistics span[style*="background:#312e81"] { background: #f0f0f0 !important; color: #000 !important; border: 1px solid #999 !important; }

  /* Tables / charts */
  .chart-container, [id^="plot-"], svg, table { break-inside: avoid; page-break-inside: avoid; }

  table { border-collapse: collapse; width: 100%; font-size: 9.5pt; }
  table td, table th { border: 1px solid #888 !important; padding: 4px 6px !important; }
  table th { background: #eee !important; font-weight: bold; }

  @page { margin: 1.5cm 1.4cm 1.8cm 1.4cm; size: A4; }
  @page :first { margin-top: 1.2cm; }

  /* Headings */
  h1, h2, h3 { page-break-after: avoid; color: #000 !important; }
  h1 { font-size: 16pt; }
  h2 { font-size: 13pt; margin-top: 14px; }
  h3 { font-size: 11pt; margin-top: 10px; }

  a { color: #000; text-decoration: underline; }
  a[href^="http"]::after { content: " [" attr(href) "]"; font-size: 8pt; color: #444; }

  /* Suppress the in-page collapse arrows */
  .ph-arrow, .suite-arrow { display: none !important; }

  /* Page numbers */
  body::after { content: ""; }
}
    `;
  }

  function buildHeader() {
    const h1 = document.querySelector('h1');
    const title = h1 ? (h1.textContent || '').trim() : (document.title || '');
    const url = location.href;
    const date = new Date().toISOString().slice(0, 10);
    const cfg = global.NMA_CONFIG || (global.RapidMeta && global.RapidMeta.state && global.RapidMeta.state.protocol);
    const pico = cfg && cfg.protocol ? cfg.protocol : (cfg || {});
    const pop = pico.pop || pico.population || '—';
    const intervention = pico.int || pico.intervention || '—';
    const comp = pico.comp || pico.comparator || '—';
    const out = pico.out || pico.outcome || '—';
    const ver = (cfg && cfg.version) || '—';

    const div = document.createElement('div');
    div.id = 'cochrane-export-header';
    div.style.cssText = 'background:white;color:black;font-family:Times New Roman, Georgia, serif;';
    div.innerHTML =
      '<div style="font-size:8pt;letter-spacing:0.05em;text-transform:uppercase;color:#666;margin-bottom:4px;">RevMan-compatible synthesis · ' + date + ' · v' + ver + '</div>' +
      '<h1 style="font-size:16pt;margin:0 0 6px 0;font-weight:bold;">' + escapeHtml(title) + '</h1>' +
      '<table style="width:100%;font-size:9.5pt;margin-top:6px;border-collapse:collapse;">' +
        '<tr><td style="padding:2px 6px;border:1px solid #888;background:#f5f5f5;font-weight:bold;width:18%;">Population</td>' +
            '<td style="padding:2px 6px;border:1px solid #888;">' + escapeHtml(pop) + '</td></tr>' +
        '<tr><td style="padding:2px 6px;border:1px solid #888;background:#f5f5f5;font-weight:bold;">Intervention</td>' +
            '<td style="padding:2px 6px;border:1px solid #888;">' + escapeHtml(intervention) + '</td></tr>' +
        '<tr><td style="padding:2px 6px;border:1px solid #888;background:#f5f5f5;font-weight:bold;">Comparator</td>' +
            '<td style="padding:2px 6px;border:1px solid #888;">' + escapeHtml(comp) + '</td></tr>' +
        '<tr><td style="padding:2px 6px;border:1px solid #888;background:#f5f5f5;font-weight:bold;">Primary outcome</td>' +
            '<td style="padding:2px 6px;border:1px solid #888;">' + escapeHtml(out) + '</td></tr>' +
        '<tr><td style="padding:2px 6px;border:1px solid #888;background:#f5f5f5;font-weight:bold;">Source</td>' +
            '<td style="padding:2px 6px;border:1px solid #888;font-family:monospace;font-size:8.5pt;">' + escapeHtml(url) + '</td></tr>' +
      '</table>';
    return div;
  }

  function buildFooter() {
    const div = document.createElement('div');
    div.id = 'cochrane-export-footer';
    div.style.cssText = 'background:white;color:black;font-family:Times New Roman, Georgia, serif;';
    div.innerHTML =
      '<div><strong>Disclaimer:</strong> Generated by RapidMeta. <em>Not a Cochrane Collaboration document.</em> ' +
      'This report is a RevMan-compatible synthesis using DerSimonian–Laird random-effects with HKSJ ' +
      'CI adjustment and Cochrane Handbook v6.5 prediction-interval convention (t<sub>k−1</sub>). ' +
      'Where shown, the R metafor 4.8.0 result is a cross-validation of the in-page JS engine; ' +
      'GRADE certainty is reviewer-attestable. Per-trial integrity flags (when present) are ' +
      'pre-registration concordance heuristics from public CT.gov data and do not impugn primary research integrity.</div>' +
      '<div style="margin-top:6px;font-style:normal;">Repository: ' + escapeHtml(location.origin + location.pathname) + '</div>';
    return div;
  }

  function escapeHtml(s) {
    return String(s == null ? '' : s)
      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  }

  function expandAllStatPanels(state) {
    // Open every collapsible body inside #tab-statistics
    const tab = document.getElementById('tab-statistics');
    if (!tab) return;
    const panels = tab.querySelectorAll('div[id$="-panel"], #r-validation-badge');
    panels.forEach(p => {
      const body = p.children[1];
      if (body && body.style.display === 'none') {
        state.opened.push(body);
        body.style.display = 'block';
      }
    });
  }

  function restorePanels(state) {
    state.opened.forEach(body => { body.style.display = 'none'; });
    state.opened.length = 0;
  }

  function exportPDF() {
    const state = { opened: [] };
    const reportTab = document.getElementById('tab-report');
    const statsTab = document.getElementById('tab-statistics');
    if (!reportTab) {
      alert('Scientific Output tab not found.');
      return;
    }

    // Reveal tabs temporarily
    const reportWasHidden = reportTab.classList.contains('hidden');
    const statsWasHidden = statsTab ? statsTab.classList.contains('hidden') : false;
    if (reportWasHidden) reportTab.classList.remove('hidden');
    if (statsTab && statsWasHidden) statsTab.classList.remove('hidden');

    // Open all panels in stats tab
    expandAllStatPanels(state);

    // Build header + footer if not present
    let header = document.getElementById('cochrane-export-header');
    if (!header) {
      header = buildHeader();
      document.body.insertBefore(header, document.body.firstChild);
    }
    let footer = document.getElementById('cochrane-export-footer');
    if (!footer) {
      footer = buildFooter();
      document.body.appendChild(footer);
    }

    // Inject print CSS
    const style = document.createElement('style');
    style.id = 'cochrane-export-print-style';
    style.textContent = buildPrintCSS();
    document.head.appendChild(style);

    setTimeout(() => {
      try { window.print(); } catch (e) { console.error(e); }
      setTimeout(() => {
        style.remove();
        if (header.parentNode) header.parentNode.removeChild(header);
        if (footer.parentNode) footer.parentNode.removeChild(footer);
        restorePanels(state);
        if (reportWasHidden) reportTab.classList.add('hidden');
        if (statsTab && statsWasHidden) statsTab.classList.add('hidden');
      }, 1500);
    }, 400);
  }

  function injectButton() {
    if (document.getElementById('cochrane-export-btn')) return true;
    // Find the existing "Download PDF Report" button as anchor
    const anchor = document.querySelector('button[onclick="downloadPDFReport()"]');
    if (!anchor || !anchor.parentNode) return false;
    const btn = document.createElement('button');
    btn.id = 'cochrane-export-btn';
    btn.type = 'button';
    btn.className = anchor.className.replace('bg-purple-600', 'bg-indigo-600').replace('hover:bg-purple-500', 'hover:bg-indigo-500');
    btn.innerHTML = '<i class="fa-solid fa-file-export mr-1"></i> RevMan-style PDF';
    btn.title = 'Cochrane / RevMan-compatible export including Statistics tab content';
    btn.addEventListener('click', exportPDF);
    // Insert right after the existing button
    if (anchor.nextSibling) {
      anchor.parentNode.insertBefore(btn, anchor.nextSibling);
    } else {
      anchor.parentNode.appendChild(btn);
    }
    return true;
  }

  function bootstrap() {
    if (typeof document === 'undefined') return;
    function tick() {
      injectButton();
    }
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', () => {
        let n = 0;
        const interval = setInterval(() => {
          if (injectButton()) clearInterval(interval);
          n++; if (n > 40) clearInterval(interval);
        }, 250);
      });
    } else {
      let n = 0;
      const interval = setInterval(() => {
        if (injectButton()) clearInterval(interval);
        n++; if (n > 40) clearInterval(interval);
      }, 250);
    }
  }

  global.CochraneExport = { exportPDF, injectButton };
  bootstrap();
})(typeof window !== 'undefined' ? window : this);
